var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"크윽……! 쿨럭……!","JPN":"くうっ……！　ゲホッ……！","ENG":"Krrgh...! *Cough...!*","TWN":"咳咳……！咳咳……！"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"우리가 싸우는 동안…… 애를 만신창이로 만들어 놓은 거야?","JPN":"私たちが戦ってる間に……子どもを傷つけたのか？","ENG":"While we were fighting... You beat her to a pulp?!","TWN":"你趁我們交手時……把她弄得渾身是傷嗎？"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"아, 말을 안 들어서요. 이건 제가 저로 완성되기 위한 <color=#ffd34c>제 거</color>니까.","JPN":"あ、言うことを聞かなくって。これは私が私として完成するための<color=#ffd34c>部品</color>ですから。","ENG":"Oh, this is because she wouldn't listen to me. You see, she is <color=#ffd34c>mine</color> so that I can be whole.","TWN":"誰叫她不聽話，這是我要拿來完成我的<color=#ffd34c>東西</color>。"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"그럼 언니는 잠깐 쉬고 있어요. 저 경찰은 내가 마저 혼내 줄게.","JPN":"じゃあ、ユリさんはちょっと休んでください。あの警察官は私がこらしめてあげますよ。","ENG":"Anyway Yuri, how about you take a little rest. I'll give that cop a beating for you.","TWN":"那姊姊你先休息一下，我去教訓一下那個警察。"},"stage":{"bg":"TERRA","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이런, 공범이 아직…… 아윽……","JPN":"まずい、共犯者がまだ……うぅっ……","ENG":"Damm, I didn't realize… an accomplice... Ngh...","TWN":"可惡，還有共犯……呃……"},"stage":{"bg":"TERRA","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에헷. 언니에게 칼 겨눴으니까 사냥당해도 어쩔 수 없겠네? 그치?","JPN":"えへっ。ユリさんに刃を向けたんだから、狩られても仕方ないよね？　そうでしょ？","ENG":"Hehe. Since you pointed your sword at her, you don't really have a choice but to get hunted, right?","TWN":"嘿嘿，你敢拿刀對準姊姊，那我只好進行狩獵囉？對吧？"},"stage":{"bg":"TERRA","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……그만둬.","JPN":"……やめろ。","ENG":"...Stop it.","TWN":"……住手。"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"으응~?","JPN":"ううん～？","ENG":"Hmm?","TWN":"嗯～？"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"유리 언니, 상한 우유라도 마셨어요? 저 애 언니를 죽이려고 했잖아요?","JPN":"ユリさん、腐った牛乳でも飲んじゃったんですか？　あの子、ユリさんを殺そうとしたんですよ？","ENG":"Yuri, did you drink spoiled milk or something? She tried to kill you!","TWN":"悠麗姊姊，你是喝到過期的牛奶嗎？她想殺死你欸？"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"죽이려고 한 적 없어. 체포하려고 했지.","JPN":"殺そうとしたことはない。逮捕しようとしただけだ。","ENG":"No, she didn't. She was trying to arrest me.","TWN":"她並沒有想殺我，她只是想逮補我而已。"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"오히려……. 지금은 애를 그 지경으로 만든 네가 더 문제라는 생각밖에 안 들어.","JPN":"むしろ……今はあの子をあんな風にしたお前の方が問題だとしか思えない。","ENG":"However... All I can think of now is how wrong it was for you to harm that kid.","TWN":"倒是你……把她打成那樣，我看你比較有問題吧？"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"우으~ 대장도 모자라서 언니까지 섭섭하게 그러기예요?","JPN":"うう～隊長にユリさんまで、ひどいです。","ENG":"Boo! Now you're going to talk like Captain to me?","TWN":"嗚嗚～隊長兇我還不夠，連姊姊也要讓我難過嗎？"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"애를 내려 놓고 물러서, 레비아. 나도 기껏 생긴 후임에게 이러고 싶지 않아.","JPN":"子どもを下ろして下がれ、レヴィア。私もせっかくできた後輩にこんなことしたくない。","ENG":"Put the kid down and step away, Levia. And you know I don't want to be saying this to you.","TWN":"莉維亞，把她放開後離開。我也不想對好不容易進來的後輩這樣。"},"stage":{"bg":"TERRA","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에헷. 기껏 찾은 동생이라고요. 아무리 유리 언니 부탁이라도 들어 드리기 어렵겠는데요.","JPN":"えへっ。せっかく見つけた妹なんですよ。いくらユリさんの頼みでもそれは聞いてあげられそうにないですね。","ENG":"Hehe. But she's my sister! I'm sorry, but I can't do that. Even if it's you who’s asking, Yuri.","TWN":"嘿嘿，我好不容易才找到妹妹的，就算是姊姊的請求，我也無法答應欸？"},"stage":{"bg":"TERRA","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TERRA","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"자, 그럼 다들 여기서 나가 주실래요? ","JPN":"さてと、じゃあみんなここから出てくれます？ ","ENG":"Now then, will everyone else please leave? ","TWN":"可以請大家離開這裡嗎？"},"stage":{"bg":"TERRA","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"지금 제 몸이 여기로 넘어오기에는 틈이 너무 좁거든요. 안 본 사이 살쪘나 봐.","JPN":"今、私の身体がこっちに来るには亀裂の幅が狭すぎるんですよ。少し見ない間に太ったみたい。","ENG":"The gap is too narrow for my body to come over here. It seems I gained a little bit of weight since last time.","TWN":"因為裂縫太窄，我的身體過不來，可能是一陣子沒見面有變胖吧？"},"stage":{"bg":"TERRA","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};